select  from sys_permission


        and (permission_code like concat('%', #{keyword}, '%')
             or permission_name like concat('%', #{keyword}, '%'))

    and permission_type = #{permissionType}
    and status = #{status}

order by parent_id, sort_num, id

with recursive descendants as (
    select id from sys_permission where parent_id = #{id}
    union all
    select child.id from sys_permission child
    inner join descendants parent on child.parent_id = parent.id
)
select count(1) from descendants where id = #{candidateParentId}

