update sys_permission
parent_id = #{parentId}, permission_code = #{permissionCode}, permission_name = #{permissionName}, permission_type = #{permissionType}, api_path = #{apiPath}, sort_num = #{sortNum}, description = #{description}, status = #{status}, updated_at = now()
where id = #{id}
